const e = $input.first().json;
const from = (e.from?.text || e.from?.value?.[0]?.address || e.from || '').toLowerCase();
if (!/(alfa|альфа)/i.test(from)) return [];

const subject = e.subject || '';
const rawHtml = e.html || '';
const fullBody = (e.text || e.textAsHtml || rawHtml.replace(/<[^>]+>/g, ' ')).replace(/\s+/g, ' ').trim();

const amountMatch = fullBody.match(/списана\s+сумма\s+([\d\s]+(?:[.,]\d{2})?)/i);
if (!amountMatch) {
  return [{ json: { parsed: false, subject, body: fullBody.slice(0, 1500) } }];
}
const amount = parseFloat(amountMatch[1].replace(/\s/g, '').replace(',', '.'));

const acctMatch = fullBody.match(/счёта\s+\*(\d{4})/i);
const account = acctMatch ? acctMatch[1] : null;

const dateMatch = fullBody.match(/от\s+(\d{2}\.\d{2}\.\d{2,4})/);
const txDate = dateMatch ? dateMatch[1] : null;
let isoDate = null;
if (txDate) {
  const parts = txDate.split('.');
  const yyyy = parts[2].length === 2 ? '20' + parts[2] : parts[2];
  isoDate = yyyy + '-' + parts[1].padStart(2,'0') + '-' + parts[0].padStart(2,'0');
}
const monthKey = isoDate ? isoDate.slice(0,7) : new Date().toISOString().slice(0,7);

let purpose = '';
const purposeIdx = fullBody.indexOf('Назначение платежа:');
if (purposeIdx > -1) {
  purpose = fullBody.slice(purposeIdx + 'Назначение платежа:'.length).trim();
  const cuts = ['Это сообщение', 'С уважением', 'Информация для клиентов', 'Это автоматическ'];
  for (const c of cuts) {
    const i = purpose.indexOf(c);
    if (i > -1) purpose = purpose.slice(0, i).trim();
  }
  purpose = purpose.slice(0, 500);
}

const mccMatch = fullBody.match(/MCC\s*(\d{3,4})/i);
const mcc = mccMatch ? mccMatch[1] : null;

function categorize(mcc, purpose) {
  const p = (purpose || '').toUpperCase();
  if (/(OPENAI|ANTHROPIC|CLAUDE|AWSTORE|RUNWAY|CURSOR|LOVABLE|BOLT|GITHUB|REPLIT|HETZNER|CLOUDFLARE|TIMEWEB|REG\.RU|BEGET|SELECTEL|YANDEX\.?CLOUD|DIGITAL\s*OCEAN|STABILITY|MIDJOURNEY|ELEVENLABS|NGROK|X\.AI|GROK|VERCEL|SUPABASE|FIREBASE|N8N\.IO|HEROKU|RAILWAY)/i.test(p)) return 'ИИ, серверы, костыли';
  if (/(NETFLIX|IVI|OKKO|KINOPOISK|YANDEX\.?PLUS|SBERPRIME|APPLE\.COM\/BILL|GOOGLE\*|SPOTIFY|VK\s*COMBO|YOUTUBE\s*PREMIUM|TELEGRAM\s*PREMIUM)/i.test(p)) return 'Подписки оплаты';
  if (/(ЛУКОЙЛ|LUKOIL|GAZPROMNEFT|ROSNEFT|BASHNEFT|TATNEFT|SHELL|АЗС|TEBOIL)/i.test(p)) return 'Топливо';
  if (mcc === '5541' || mcc === '5542' || mcc === '5172') return 'Топливо';
  if (/(YANDEX\s*TAXI|YANDEX\.?GO|CITYMOBIL|UBER|INDRIVE|MAXIM\s*TAXI)/i.test(p)) return 'Такси';
  if (mcc === '4121') return 'Такси';
  if (/(ДЕТСКИЙ\s*МИР|DETMIR|KARAPUZ|ДЕТСАД|САДИК|ГИМНАЗИЯ|ANTOSHKA)/i.test(p)) return 'Дети';
  if (['5641','8211','8351','8299'].includes(mcc)) return 'Дети';
  if (/(АПТЕКА|APTEKA|RIGLA|РИГЛА|ZDOROVKA|КЛИНИК|МЕДИЦИНА|ИНВИТРО|INVITRO|GEMOTEST|HELIX|FITNESS|FIT\s*HOUSE|WORLD\s*CLASS|ALEX\s*FIT|СПОРТМАСТЕР|SPORTMASTER|DECATHLON|INTERSPORT)/i.test(p)) return 'Здоровье и спорт';
  if (['8011','8021','8031','8041','8049','8050','8062','8071','8099','5912','7997','5941'].includes(mcc)) return 'Здоровье и спорт';
  if (/(ЭНЕРГО|ВОДОКАНАЛ|ГАЗПРОМ\s*МЕЖ|ЧЕЛЯБЭНЕРГО|УРАЛЭНЕРГО|УПРАВЛЯЮЩАЯ\s*КОМПАН|ЖКХ|КАПРЕМОНТ|РОСТЕЛЕКОМ|БИЛАЙН|BEELINE|МТС|МЕГАФОН|ТЕЛЕ2|TELE2|YOTA|ДОМ\.РУ|ER-?TELECOM)/i.test(p)) return 'Коммуналка';
  if (['4900','4812','4814','4899'].includes(mcc)) return 'Коммуналка';
  if (/(КРЕДИТ|KREDIT|ЗАЕМ|ZAEM|ПОГАШЕНИЕ\s+КРЕДИТА|РАССРОЧК|ИПОТЕК|IPOTEK|LEASING|ЛИЗИНГ)/i.test(p)) return 'Кредит';
  if (/(TABAK|TABAC|VAPE|VEYP|ВЕЙП|СИГАРЕТ|TOBACCO|MERCURY\s*TAB|TAB\s*SHOP|КУРИЛЬ|DOBROPAR)/i.test(p)) return 'Покурить';
  if (mcc === '5993') return 'Покурить';
  if (/(БАНЯ|САУНА|SAUNA|HOTEL|КИНОТЕАТР|АКВАПАРК|БАЗА\s*ОТДЫХА|TURIZM|PUTESHESTV)/i.test(p)) return 'Отдых';
  if (['7011','4722','4112','4511','7832','7991','7992','7993','7994','7995','7996','7998','7032','7297','7298'].includes(mcc)) return 'Отдых';
  if (/(ШТРАФ|ГИБДД|ГОСУСЛУГИ|ГОСПОШЛИНА|ВЗЫСКАН)/i.test(p)) return 'Неожид';
  if (/(МАГНИТ|MAGNIT|ПЯТЕРОЧКА|PYATEROCHKA|ПЕРЕКРЕСТОК|PEREKRESTOK|ЛЕНТА|LENTA|ДИКСИ|DIXY|АШАН|ASHAN|ОКЕЙ|OKEY|МИРАТОРГ|MIRATORG|ВКУСВИЛЛ|VKUSVILL|АЗБУКА\s*ВКУСА|АТАК|ВЕРНЫЙ|КАФЕ|CAFE|РЕСТОРАН|RESTORAN|ПИЦЦА|PIZZA|БУРГЕР|BURGER|MCDONALD|KFC|ВКУСНО|СУШИ|SUSHI|РОЛЛ|ROLL|ШАУРМА)/i.test(p)) return 'Еда';
  if (['5411','5499','5462','5451','5441','5422','5812','5814','5811','5813','5921','5471'].includes(mcc)) return 'Еда';
  if (/(WILDBERRIES|\bWB\b|ОЗОН|\bOZON\b|ЯНДЕКС\s*МАРКЕТ|YANDEX\s*MARKET|AVITO|АВИТО|ALIEXPRESS|IKEA|ИКЕЯ|HOFF|МВИДЕО|MVIDEO|ELDORADO|DNS|ОБИ|OBI|LEROY|ЛЕРУА)/i.test(p)) return 'Покупки';
  if (['5311','5651','5661','5712','5732','5933','5970','5999','5946','5621','5631','5691','5942','5945','5943','5944'].includes(mcc)) return 'Покупки';
  return null;
}

const category = categorize(mcc, purpose);
const txId = 'tx_' + Date.now() + '_' + Math.random().toString(36).slice(2,5);
const tx = { id: txId, type: 'spending', amount, account, txDate, isoDate, monthKey, purpose, mcc, category, subject };

return [{ json: Object.assign({ parsed: true }, tx) }];
